"""Seed knowledge base tables — idempotent, runs on every startup."""
import logging
from bot.db.database import get_cursor

logger = logging.getLogger(__name__)


def _table_has_data(cur, table: str) -> bool:
    cur.execute(f"SELECT EXISTS(SELECT 1 FROM {table} LIMIT 1)")
    return cur.fetchone()[0]


def _sv(text: str) -> str:
    """Build tsvector SQL expression."""
    return text


