# EXPERT KNOWLEDGE — ~80 curated entries from top health experts
# ═══════════════════════════════════════════════════════════════════════

def seed_expert_knowledge():
    with get_cursor(dict_cursor=False) as cur:
        if _table_has_data(cur, "knowledge_base"):
            logger.info("knowledge_base already seeded, skipping")
            return
        # (category, topic, title, content, source, tags, evidence_level)
        entries = [
            # ── HUBERMAN (~25 entries) ──
            ("longevity", "cold_exposure", "Cold Exposure Protocol", "Deliberate cold exposure for 11 minutes total per week across 2-4 sessions. Water temperature 40-60F. End on cold (not warm). Triggers norepinephrine 2-3x increase lasting hours. Dopamine increases 2.5x baseline for hours. Improves metabolism, mood, resilience, and immune function.", "huberman", ["cold", "dopamine", "metabolism", "resilience"], "A"),
            ("longevity", "heat_exposure", "Sauna Protocol for Longevity", "Sauna 4x per week at 80-100C (176-212F) for 20 min per session. Associated with 40% reduction in all-cause mortality (Laukkanen Finnish study). Increases growth hormone up to 16x with specific protocols. Triggers heat shock proteins for cellular repair. Best done after training, not before.", "huberman", ["sauna", "heat", "longevity", "growth_hormone"], "A"),
            ("sleep", "sleep_toolkit", "Huberman Sleep Toolkit", "1) Morning sunlight 10 min within 30-60 min of waking. 2) Delay caffeine 90-120 min after waking. 3) Cool room 65-68F. 4) Magnesium threonate 30-60 min before bed. 5) Avoid bright lights 10pm-4am. 6) NSDR (Non-Sleep Deep Rest) for sleep recovery. 7) Consistent wake time is most important anchor.", "huberman", ["sleep", "circadian", "light", "magnesium"], "A"),
            ("neuroscience", "dopamine_management", "Dopamine Management Protocol", "Avoid chronic dopamine-spiking behaviors (social media, porn, sugar). Intermittent reward schedules build motivation. Cold exposure provides sustained dopamine boost. Stack dopamine layers carefully — don't combine too many stimulants. Occasional dopamine fasts (24-48h minimal stimulation) can reset baseline.", "huberman", ["dopamine", "motivation", "focus", "addiction"], "B"),
            ("longevity", "light_exposure", "Morning Sunlight Protocol", "Get 10 min of direct sunlight within 30-60 min of waking. Cloudy days need 20-30 min. Never through a window or sunglasses. Sets circadian clock via melanopsin cells in retina. Triggers cortisol pulse that improves alertness, mood, and evening melatonin production. Single most important behavioral tool for sleep.", "huberman", ["light", "circadian", "cortisol", "melatonin"], "A"),
            ("neuroscience", "focus_protocols", "Focus and Concentration Protocols", "90-minute focused work blocks align with ultradian cycles. Visual focus drives cognitive focus — stare at a point to engage prefrontal circuits. Caffeine + L-theanine is effective focus stack. Alpha-GPC 300mg pre-focus. White noise or binaural beats (40Hz) can help. Deliberate defocus periods between blocks.", "huberman", ["focus", "concentration", "nootropics", "productivity"], "B"),
            ("supplements", "caffeine_protocol", "Caffeine Optimization", "Delay caffeine 90-120 min after waking to avoid afternoon crash. Adenosine needs time to clear naturally upon waking. Caffeine half-life is 5-6 hours — set a cutoff. 1-3mg/kg is optimal dose. Combine with L-theanine 100-200mg to remove jitters. Cycling off periodically restores sensitivity.", "huberman", ["caffeine", "adenosine", "energy", "focus"], "A"),
            ("recovery", "nsdr_protocol", "Non-Sleep Deep Rest (NSDR)", "10-20 minute guided relaxation combining yoga nidra elements. Restores mental and physical energy. Can partially replace lost sleep. Enhances neuroplasticity and learning consolidation. Best done early afternoon or when tired. Free NSDR scripts available. Reduces cortisol and improves dopamine regulation.", "huberman", ["nsdr", "yoga_nidra", "recovery", "neuroplasticity"], "B"),
            ("neuroscience", "stress_management", "Physiological Sigh for Real-Time Stress", "Double inhale through nose (one full, one quick top-off) followed by long exhale through mouth. Single most effective real-time stress reduction tool. Works in 1-3 breaths. Activates parasympathetic via phrenic nerve. Can be done anywhere without anyone noticing. Superior to box breathing for acute stress.", "huberman", ["stress", "breathing", "parasympathetic", "anxiety"], "A"),
            ("hormones", "testosterone_optimization", "Natural Testosterone Optimization", "Sleep 7-9 hours (most important factor). Resistance training with compound movements. Vitamin D 5000+ IU. Zinc 30mg. Tongkat Ali 400mg. Fadogia Agrestis 600mg (with caution). Cold exposure. Reduce alcohol. Maintain body fat 10-20%. Morning sunlight. Manage stress.", "huberman", ["testosterone", "hormones", "supplements", "training"], "B"),
            ("supplements", "magnesium_sleep", "Magnesium Threonate for Sleep", "Magnesium L-threonate (Magtein) is the only form proven to cross the blood-brain barrier. Take 144mg elemental magnesium (about 2g threonate) 30-60 min before bed. Enhances GABA signaling and promotes relaxation. More effective for sleep than glycinate or citrate for brain effects.", "huberman", ["magnesium", "sleep", "gaba", "brain"], "B"),
            ("fitness", "zone2_huberman", "Huberman on Zone 2 Cardio", "Zone 2 cardio (can maintain nasal breathing, could hold conversation) for 150-200 min per week is foundational for cardiovascular health and metabolic flexibility. Can be walking, cycling, swimming. Builds mitochondrial density. Enhances fat oxidation. Foundation for all other training.", "huberman", ["zone2", "cardio", "mitochondria", "metabolic"], "A"),
            # ── ATTIA (~20 entries) ──
            ("fitness", "zone2_cardio", "Zone 2 Cardio — Foundation of Fitness", "Zone 2 is the highest intensity where lactate remains stable (~2 mmol/L). 3-4 hours per week minimum. This is the single most important exercise modality for longevity. Builds mitochondrial density, improves fat oxidation, enhances metabolic flexibility. Can be cycling, rowing, swimming, brisk walking.", "attia", ["zone2", "cardio", "mitochondria", "longevity"], "A"),
            ("fitness", "vo2max", "VO2 Max — Strongest Longevity Predictor", "VO2 max is the single strongest predictor of all-cause mortality — stronger than smoking, diabetes, or cardiovascular disease. Moving from bottom 25th percentile to 50th reduces mortality risk by 50%. Moving to top 2.5% (elite) reduces by 80%. Train with 4x4 min high-intensity intervals 1-2x per week.", "attia", ["vo2max", "cardio", "longevity", "mortality"], "A"),
            ("longevity", "centenarian_decathlon", "Centenarian Decathlon Concept", "Define 10 physical tasks you want to do at age 100 (carry groceries, climb stairs, get off floor, play with grandchildren, etc). Work backward to determine what strength, cardio, flexibility you need NOW. Train with 20% margin above those requirements. This reframes exercise as longevity medicine, not vanity.", "attia", ["longevity", "fitness", "aging", "functional"], "B"),
            ("fitness", "stability_training", "Stability as Foundation", "Stability training should be the foundation before loading patterns. DNS (Dynamic Neuromuscular Stabilization) principles. Foot stability, hip stability, scapular control. Without stability, you're loading dysfunction. 10-15 min daily stability work prevents injuries and improves performance.", "attia", ["stability", "mobility", "injury_prevention", "dns"], "B"),
            ("cardiovascular", "apob_marker", "ApoB — The Key Lipid Marker", "ApoB is the single best predictor of cardiovascular risk from lipids. One ApoB molecule per atherogenic particle. Target <80 mg/dL (some argue <60 for high risk). More predictive than LDL-C because it counts actual particles. Measure early. Act early. Cardiovascular disease is the #1 killer.", "attia", ["apob", "lipids", "cardiovascular", "cholesterol"], "A"),
            ("longevity", "sleep_pillar", "Sleep as Longevity Pillar", "Sleep is one of the four pillars of longevity (with exercise, nutrition, emotional health). 7-9 hours consistently. Sleep deprivation increases ApoB, insulin resistance, inflammation, and cortisol. It's not optional — it's medicine. Track with WHOOP or Oura. Consistency of timing matters more than duration.", "attia", ["sleep", "longevity", "recovery", "hormones"], "A"),
            ("longevity", "emotional_health", "Emotional Health Framework", "Emotional health is the forgotten pillar of longevity. No point living to 100 in misery. Therapy, relationships, purpose, stress management. Attia's personal journey with anger and emotional regulation. Bridge metaphor: you can build the most structurally sound bridge (body), but without the road (emotional health), it's useless.", "attia", ["emotional_health", "mental_health", "longevity", "relationships"], "B"),
            ("metabolic", "glucose_management", "Glucose Management for Longevity", "Stable glucose is foundational for metabolic health. Use CGM to learn your response to foods. Target average glucose <100 mg/dL. Minimize spikes >140. Post-meal walks dramatically reduce glucose spikes. Resistance training improves glucose disposal. Time carbs around exercise.", "attia", ["glucose", "metabolic", "cgm", "insulin"], "A"),
            ("fitness", "grip_strength", "Grip Strength as Longevity Marker", "Grip strength is one of the strongest predictors of all-cause mortality. It's a proxy for overall strength and functional capacity. Dead hangs, farmer carries, and dedicated grip work. Test with dynamometer. Aim to maintain or improve throughout life.", "attia", ["grip", "strength", "longevity", "mortality"], "A"),
            ("longevity", "exercise_is_medicine", "Exercise Is the Most Powerful Longevity Drug", "If exercise were a drug, it would be the most prescribed medicine in history. Reduces all-cause mortality more than any pharmaceutical intervention. Minimum effective dose: 150 min zone 2 + 2-3 strength sessions per week. The dose-response curve is steep — even small amounts dramatically reduce risk.", "attia", ["exercise", "longevity", "mortality", "medicine"], "A"),
            ("longevity", "four_horsemen", "The Four Horsemen of Chronic Disease", "Attia's framework: the four leading causes of death in developed nations are cardiovascular disease, cancer, neurodegenerative disease, and metabolic disease. Prevention strategy must address all four simultaneously. Exercise, nutrition, sleep, and emotional health are the interventions.", "attia", ["longevity", "disease", "prevention", "framework"], "A"),
            # ── SINCLAIR (~15 entries) ──
            ("longevity", "nad_sirtuins", "NAD+ and Sirtuin Pathway", "NAD+ declines with age and is essential for sirtuin enzyme function. Sirtuins (SIRT1-7) regulate DNA repair, inflammation, and metabolic processes. NMN (nicotinamide mononucleotide) at 1g/day replenishes NAD+. Resveratrol 1g/day activates sirtuins. Together they form the core of Sinclair's longevity protocol.", "sinclair", ["nad", "sirtuins", "nmn", "longevity"], "B"),
            ("longevity", "information_theory_aging", "Information Theory of Aging", "Aging is not random damage but loss of epigenetic information. DNA is the digital information (hardware), epigenome is the analog reader (software). As cells repair DNA breaks, they lose epigenetic marks. Yamanaka factors can reset the epigenome, potentially reversing biological age.", "sinclair", ["epigenetics", "aging", "yamanaka", "dna_repair"], "C"),
            ("longevity", "fasting_benefits", "Fasting and Longevity", "Fasting activates survival pathways: AMPK, sirtuins, autophagy. Time-restricted feeding (16:8 minimum) provides benefits. 24-48 hour fasts trigger deeper autophagy. Fasting mimetics (metformin, rapamycin, berberine) activate similar pathways. Don't eat when not hungry. Your body has built-in fasting mechanisms — use them.", "sinclair", ["fasting", "autophagy", "ampk", "longevity"], "B"),
            ("longevity", "epigenetic_clock", "Epigenetic Clock and Biological Age", "DNA methylation patterns accurately predict biological age (Horvath clock). Biological age can differ significantly from chronological age. Lifestyle interventions can reverse epigenetic age: exercise, sleep, nutrition, supplements. Testing available via TruAge and similar services. Track over time.", "sinclair", ["epigenetics", "aging", "methylation", "biological_age"], "B"),
            ("longevity", "metformin_debate", "The Metformin Debate", "Metformin activates AMPK and has shown longevity benefits in observational studies. The TAME trial will provide definitive evidence. Concerns: may blunt exercise adaptation (mTOR inhibition). Sinclair takes it. Attia is more cautious. Alternative: berberine provides similar AMPK activation without prescription.", "sinclair", ["metformin", "ampk", "longevity", "debate"], "C"),
            ("longevity", "cold_longevity", "Cold Exposure for Longevity Pathways", "Cold activates brown adipose tissue, increases norepinephrine, activates sirtuins and AMPK. Cold shock proteins (RBM3) may protect against neurodegeneration. Regular cold exposure is hormetic stress that builds cellular resilience. Even cold showers provide meaningful activation of longevity pathways.", "sinclair", ["cold", "brown_fat", "hormesis", "longevity"], "B"),
            ("supplements", "sinclair_protocol", "Sinclair's Personal Supplement Protocol", "NMN 1g/day (morning). Resveratrol 1g/day (with yogurt for fat absorption). Metformin 1g/day (not on exercise days). Vitamin D. Vitamin K2. Low-dose aspirin. Spermidine. Fisetin (periodic). Aims for intermittent fasting and plant-heavy diet. Exercises daily.", "sinclair", ["nmn", "resveratrol", "metformin", "protocol"], "C"),
            ("longevity", "xenohormesis", "Xenohormesis — Plant Stress Molecules", "Stressed plants produce polyphenols (resveratrol, quercetin, fisetin) that activate human stress response pathways when consumed. This cross-species hormetic signaling (xenohormesis) means eating stressed, organic, colorful plants provides longevity benefits beyond basic nutrition.", "sinclair", ["xenohormesis", "polyphenols", "resveratrol", "plants"], "C"),
            ("longevity", "rapamycin_research", "Rapamycin and mTOR Inhibition", "Rapamycin inhibits mTOR, a nutrient-sensing pathway that promotes growth but accelerates aging when chronically active. Low-dose rapamycin shows longevity extension in animal models. Some longevity physicians prescribe low-dose pulsed protocols. Trade-off: immune suppression at higher doses.", "sinclair", ["rapamycin", "mtor", "longevity", "immune"], "C"),
            # ── LYON (~10 entries) ──
            ("nutrition", "muscle_centric_medicine", "Muscle-Centric Medicine", "Muscle is the organ of longevity. It's the largest glucose disposal site, the amino acid reservoir, a signaling organ (myokines), and the primary determinant of metabolic health. Prioritize building and maintaining muscle above all other health interventions. Sarcopenia (muscle loss) is the aging accelerator.", "lyon", ["muscle", "longevity", "metabolic", "sarcopenia"], "A"),
            ("nutrition", "protein_intake", "Protein: 1g per Pound of Ideal Body Weight", "Aim for 1g protein per pound of ideal body weight per day. This is higher than RDA (0.36g/lb) but supported by research for body composition and aging. Distribute across 3-4 meals. First meal of day should be protein-heavy (30-50g). Animal protein is most bioavailable.", "lyon", ["protein", "nutrition", "muscle", "amino_acids"], "A"),
            ("nutrition", "leucine_threshold", "Leucine Threshold for Muscle Protein Synthesis", "Each meal needs 2.5-3g of leucine to maximally stimulate muscle protein synthesis via mTOR activation. This equals roughly 30-40g of animal protein per meal. Plant proteins require much larger portions to hit leucine threshold. This is the single most important meal planning metric.", "lyon", ["leucine", "mtor", "protein", "muscle"], "A"),
            ("longevity", "sarcopenia_prevention", "Sarcopenia Prevention Strategy", "Muscle mass declines 3-8% per decade after 30, accelerating after 60. By 80, you've lost 30-50% of muscle. Prevention requires: 1) Adequate protein (1g/lb), 2) Resistance training 3-4x/week, 3) Leucine at every meal, 4) Creatine supplementation, 5) Vitamin D optimization. Start NOW.", "lyon", ["sarcopenia", "aging", "muscle", "prevention"], "A"),
            ("nutrition", "protein_distribution", "Protein Distribution Across Meals", "Don't backload protein to dinner. Spread across 3-4 meals with 30-50g each. First meal should have the most protein to set leucine/mTOR signaling for the day. Avoid protein-free meals. Pre-sleep casein or Greek yogurt can support overnight muscle protein synthesis.", "lyon", ["protein", "meals", "distribution", "mtor"], "B"),
            ("fitness", "resistance_training_lyon", "Resistance Training as #1 Intervention", "If you could only do one thing for your health, it should be resistance training. It builds muscle (longevity organ), improves insulin sensitivity, increases bone density, reduces all-cause mortality, improves cognitive function, and prevents falls. 3-4 sessions per week, progressive overload.", "lyon", ["resistance_training", "muscle", "strength", "longevity"], "A"),
            # ── DOAC (~10 entries) ──
            ("gut_health", "gut_microbiome", "Gut Microbiome Diversity (Tim Spector)", "Diversity of gut bacteria is the #1 indicator of gut health. Aim for 30+ different plants per week. Fermented foods daily (kefir, kimchi, sauerkraut, kombucha). Artificial sweeteners devastate gut bacteria. Ultra-processed foods reduce diversity. Your microbiome changes in days with diet changes.", "doac", ["gut", "microbiome", "diversity", "fermented"], "A"),
            ("nutrition", "ultra_processed_foods", "Ultra-Processed Foods (Chris van Tulleken)", "Ultra-processed foods (UPFs) make up 60%+ of calories in Western diets. They override satiety signals, cause inflammation, damage gut microbiome, and are engineered to be addictive. The processing itself — not just the ingredients — causes harm. If it has ingredients you wouldn't find in a kitchen, it's UPF.", "doac", ["upf", "processed", "nutrition", "inflammation"], "A"),
            ("longevity", "five_pillars_health", "Five Pillars of Health (Rangan Chatterjee)", "1) Relaxation (stress management, breathing, nature). 2) Food (whole foods, time-restricted eating). 3) Movement (daily activity, strength training). 4) Sleep (7-9 hours, consistent schedule). These four create the fifth: Purpose and connection. Health is simple — we've overcomplicated it.", "doac", ["pillars", "health", "lifestyle", "holistic"], "B"),
            ("mental_health", "stress_gut_connection", "Stress-Gut-Brain Axis", "Chronic stress directly damages gut lining, reduces microbiome diversity, increases intestinal permeability (leaky gut), and triggers systemic inflammation. This creates a feedback loop: poor gut health worsens mental health. Probiotics, fermented foods, and stress management break the cycle.", "doac", ["stress", "gut_brain", "inflammation", "mental_health"], "B"),
            ("nutrition", "sugar_impact", "Sugar: The Hidden Health Destroyer", "Added sugar is the #1 dietary contributor to chronic disease. Average consumption is 73g/day vs recommended <25g. Causes insulin resistance, liver fat, inflammation, and feeds harmful gut bacteria. Liquid sugar (soda, juice) is worst — no fiber to slow absorption. Two-week sugar elimination resets taste buds.", "doac", ["sugar", "metabolic", "insulin", "inflammation"], "A"),
            ("fitness", "movement_vs_exercise", "Daily Movement vs Structured Exercise", "NEAT (non-exercise activity thermogenesis) accounts for more daily calorie burn than workouts. Walking 8000-10000 steps per day reduces all-cause mortality by 50%. Take stairs, walk meetings, stand while working. Structured exercise ON TOP of daily movement, not instead of it.", "doac", ["movement", "neat", "walking", "daily_activity"], "A"),
            ("sleep", "sleep_consistency", "Sleep Consistency Matters More Than Duration", "Going to bed and waking at the same time every day (including weekends) is more impactful than total sleep duration. Irregular sleep schedules increase cardiovascular risk, metabolic dysfunction, and mood disorders. Set a non-negotiable wake time. Your body clock doesn't know it's Saturday.", "doac", ["sleep", "circadian", "consistency", "health"], "A"),
            ("nutrition", "eat_the_rainbow", "Eat 30 Plants Per Week", "Spector's research shows gut microbiome diversity correlates strongly with the number of different plant species consumed weekly. Target 30+ different plants including vegetables, fruits, nuts, seeds, herbs, spices, and whole grains. Each plant feeds different bacterial species. Count herbs and spices.", "doac", ["plants", "diversity", "microbiome", "nutrition"], "A"),
        ]
        for e in entries:
            cat, topic, title, content, source, tags, ev = e
            sv_text = f"{title} {topic} {content} {source} {' '.join(tags)}"
            cur.execute(
                """INSERT INTO knowledge_base
                   (category, topic, title, content, source, tags, evidence_level, search_vector)
                   VALUES (%s, %s, %s, %s, %s, %s, %s, to_tsvector('english', %s))""",
                (cat, topic, title, content, source, tags, ev, sv_text),
            )
        logger.info(f"Seeded {len(entries)} expert knowledge entries")


